mapper.select:
SELECT i.*, s.site_name, s.band, o.operator_name
FROM indicator_info i
JOIN site_info s ON i.site_id = s.id
JOIN operator_info o ON s.operator_id = o.id
WHERE 1=1

    AND o.operator_name = #{operatorName}


    AND s.site_code = #{siteCode}


    AND i.data_time = #{dataTime}


    AND i.data_time = (SELECT MAX(data_time) FROM indicator_info)

ORDER BY i.data_time DESC
LIMIT #{limit}

SELECT i.*, s.site_name, s.band, o.operator_name
FROM indicator_info i
JOIN site_info s ON i.site_id = s.id
JOIN operator_info o ON s.operator_id = o.id
WHERE i.data_time = (SELECT MAX(data_time) FROM indicator_info)

    AND o.operator_name = #{operatorName}


    AND s.band IN

        #{band}


ORDER BY i.prb_usage DESC
LIMIT #{limit}

SELECT i.*, s.site_name, s.band, o.operator_name
FROM indicator_info i
JOIN site_info s ON i.site_id = s.id
JOIN operator_info o ON s.operator_id = o.id
WHERE i.data_time = #{dataTime}

    AND o.operator_name = #{operatorName}


    AND s.site_code = #{siteCode}

LIMIT #{limit}

SELECT i.*, s.site_name, s.band, o.operator_name,
       DATE_FORMAT(i.data_time, '%Y-%m') as data_month
FROM indicator_info i
JOIN site_info s ON i.site_id = s.id
JOIN operator_info o ON s.operator_id = o.id
WHERE DATE_FORMAT(i.data_time, '%Y-%m') = #{yearMonth}

    AND o.operator_name = #{operatorName}


    AND s.site_code = #{siteCode}

ORDER BY i.data_time DESC
LIMIT #{limit}

SELECT i.data_time, i.cell_id, i.cell_name, s.site_name, o.operator_name,
       i.dl_rate, i.ul_rate, i.prb_usage, i.split_ratio, i.main_ratio, s.band
FROM indicator_info i
JOIN site_info s ON i.site_id = s.id
JOIN operator_info o ON s.operator_id = o.id
WHERE i.data_time BETWEEN #{startTime} AND #{endTime}

    AND o.operator_name = #{operatorName}


    AND s.site_code = #{siteCode}


    AND i.cell_id = #{cellId}

ORDER BY i.data_time ASC
LIMIT #{limit}

SELECT DISTINCT DATE_FORMAT(i.data_time, '%Y-%m') as year_month, COUNT(*) as record_count, MIN(i.data_time) as first_record, MAX(i.data_time) as last_record FROM indicator_info i JOIN site_info s ON i.site_id = s.id JOIN operator_info o ON s.operator_id = o.id WHERE 1=1
AND o.operator_name = #{operatorName}
AND s.site_code = #{siteCode}
GROUP BY year_month ORDER BY year_month DESC LIMIT #{limit}
